import React, {useState, useRef} from 'react';
import axios from 'axios';

export default function Chat({messages, setMessages}){
  const [text,setText] = useState('');
  const [loading,setLoading] = useState(false);
  const [uploading,setUploading] = useState(false);
  const fileRef = useRef();

  async function send(){
    if(!text) return;
    setMessages(m=>[...m,{role:'user',text}]);
    setLoading(true);
    const form = new FormData();
    form.append('message', text);
    try{
      const res = await axios.post('/api/chat', form);
      const reply = res.data.reply || 'No reply';
      if(res.data.blocked){
        setMessages(m=>[...m,{role:'assistant',text:reply,blocked:true}]);
      } else if(res.data.redflag){
        setMessages(m=>[...m,{role:'assistant',text:reply,redflag:true}]);
      } else {
        setMessages(m=>[...m,{role:'assistant',text:reply}]);
      }
    }catch(e){
      setMessages(m=>[...m,{role:'assistant',text:'Error contacting server'}]);
    } finally {
      setText('');
      setLoading(false);
    }
  }

  async function uploadFile(e){
    const f = e.target.files[0];
    if(!f) return;
    setUploading(true);
    const form = new FormData();
    form.append('file', f);
    try{
      const res = await axios.post('/api/upload', form, {
        headers: {'Content-Type': 'multipart/form-data'}
      });
      const filename = res.data.filename || 'uploaded';
      setMessages(m=>[...m,{role:'assistant',text:`File uploaded: ${filename}`}]);
    }catch(err){
      setMessages(m=>[...m,{role:'assistant',text:'Upload failed'}]);
    } finally {
      setUploading(false);
      if(fileRef.current) fileRef.current.value = null;
    }
  }

  return (
    <div>
      <div style={{border:'1px solid #ddd',padding:10,height:300,overflow:'auto'}}>
        {(messages || []).map((m,i)=>(
          <div key={i} style={{marginBottom:8}}>
            <strong style={{textTransform:'capitalize'}}>{m.role}:</strong>
            <span style={{marginLeft:8}}>{m.text}</span>
            {m.blocked && <span style={{color:'red',marginLeft:8}}> (blocked)</span>}
            {m.redflag && <span style={{color:'orange',marginLeft:8}}> (red-flag)</span>}
          </div>
        ))}
      </div>
      <div style={{marginTop:8,display:'flex',gap:8,alignItems:'center'}}>
        <input value={text} onChange={e=>setText(e.target.value)} style={{flex:1}} disabled={loading} />
        <button onClick={send} disabled={loading}>{loading ? 'Sending...' : 'Send'}</button>
      </div>
      <div style={{marginTop:8}}>
        <input type="file" onChange={uploadFile} ref={fileRef} disabled={uploading} />
        {uploading && <span style={{marginLeft:8}}>Uploading...</span>}
      </div>
    </div>
  )
}
